// Script: generar_110_modulo_reproductivo.js
// Que hace: agrega el modulo reproductivo completo a CHIQUI.
//
// IMPORTANTE: primero correr 14_reproduccion.sql en Supabase
//
// FLUJO:
//   Al crear mascota: si es Hembra, pregunta si quiere seguimiento
//   reproductivo y su estado (esterilizada / no esterilizada / no sé).
//
//   En Prevencion: nueva seccion "🌸 Reproduccion" (solo hembras con
//   seguimiento activado). Permite registrar:
//     - Ciclos: celo, embarazo, lactancia con fechas y duracion
//     - Linea de vida: primer celo, esterilizacion, embarazo, parto,
//       lactancia, tumor mamario, otro — con fecha y notas
//   Muestra prediccion del proximo celo con 2+ celos registrados.
//
//   En Dashboard: tarjeta especial "🌸 Lucy esta en celo · Dia X"
//   cuando detecta un celo activo hoy.
//
//   1) components/ReproduccionTracker.tsx (NUEVO)
//   2) app/prevencion/page.tsx
//   3) components/DashboardContenido.tsx
//   4) app/dashboard/page.tsx
//   5) app/mascota/nueva/page.tsx

const fs = require('fs'); const path = require('path');
function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64,'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir,{recursive:true});
  fs.writeFileSync(filePath, content, 'utf8');
  const exp = (content.match(/export default/g)||[]).length;
  console.log('OK: ' + filePath + ' (exports: ' + exp + ')');
}
escribir('components/ReproduccionTracker.tsx', "");
escribir('app/prevencion/page.tsx', "");
escribir('components/DashboardContenido.tsx', "");
escribir('app/dashboard/page.tsx', "");
escribir('app/mascota/nueva/page.tsx', "");
